// Geist (woff), base64-embedded so the OG route loads fonts with zero fs/fetch —
// works in every runtime and gets bundled. Regenerate if the .woff files change.
const decode = (s: string): Buffer => Buffer.from(s, 'base64');

export const geist400 = decode('');
export const geist700 = decode('');
export const geist800 = decode('');
